import{_ as a,c as s,o as r,b as t}from"./app.81e64653.js";var n="/assets/Atma-shatakam-04.068b2de1.svg";const u='{"title":"\u0428\u0438\u0432\u0430 \u0448\u0430\u0434\u0430\u043A\u0448\u0430\u0440\u0430 \u0441\u0442\u043E\u0442\u0440\u0430","description":"","frontmatter":{"title":"\u0428\u0438\u0432\u0430 \u0448\u0430\u0434\u0430\u043A\u0448\u0430\u0440\u0430 \u0441\u0442\u043E\u0442\u0440\u0430","subtitle":"\u0413\u0438\u043C\u043D \u0448\u0435\u0441\u0442\u0438 \u0441\u043B\u043E\u0433\u0430\u043C \u043C\u0430\u043D\u0442\u0440\u044B \u0428\u0438\u0432\u044B","sans":"\u0936\u094D\u0930\u0940\u0936\u093F\u0935\u0937\u0921\u0915\u094D\u0937\u0930\u0938\u094D\u0924\u094B\u0924\u094D\u0930\u092E\u094D","trans":"\u015Br\u012B\u015Biva\u1E63a\u1E0Dak\u1E63arastotram","date":"2021-06-06T00:00:00.000Z","tags":"hymn"},"headers":[{"level":2,"title":"\u0412\u0430\u0440\u0438\u0430\u043D\u0442 \u0430\u043A\u043A\u043E\u043C\u043F\u0430\u043D\u0435\u043C\u0435\u043D\u0442\u0430","slug":"\u0432\u0430\u0440\u0438\u0430\u043D\u0442-\u0430\u043A\u043A\u043E\u043C\u043F\u0430\u043D\u0435\u043C\u0435\u043D\u0442\u0430"}],"relativePath":"hymns/shadakshara/index.md"}',p={},i=t('<p>\u0421\u0442\u0438\u0445\u043E\u0442\u0432\u043E\u0440\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0441 \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442\u0430: \u041D\u0430\u0442\u0430\u043D \u0411\u0440\u0430\u0441\u043B\u0430\u0432\u0441\u043A\u0438. \u0412 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u043C \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043E\u0445\u0440\u0430\u043D\u0451\u043D \u0441\u0442\u0438\u0445\u043E\u0442\u0432\u043E\u0440\u043D\u044B\u0439 \u0440\u0430\u0437\u043C\u0435\u0440 \u043E\u0440\u0438\u0433\u0438\u043D\u0430\u043B\u0430 (\u0430\u043D\u0443\u0448\u0442\u0443\u0431\u0445), \u0442\u043E \u0435\u0441\u0442\u044C \u043A\u0430\u0436\u0434\u0430\u044F \u0441\u0442\u0440\u043E\u0444\u0430 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 32-\u0445 \u0441\u043B\u043E\u0433\u043E\u0432, \u043A\u0430\u0436\u0434\u044B\u0439 8-\u043E\u0439 \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0441\u0438\u043B\u044C\u043D\u044B\u043C.</p><div class="stanza"><a href="#s1" id="s1" class="num">1</a><p class="sans">\u0950\u0915\u093E\u0930\u0902 \u092C\u093F\u0902\u0926\u0941\u0938\u0902\u092F\u0941\u0915\u094D\u0924\u0902 \u0928\u093F\u0924\u094D\u092F\u0902 \u0927\u094D\u092F\u093E\u092F\u0902\u0924\u093F \u092F\u094B\u0917\u093F\u0928\u0903 \u0964<br> \u0915\u093E\u092E\u0926\u0902 \u092E\u094B\u0915\u094D\u0937\u0926\u0902 \u091A\u0948\u0935 \u0950\u0915\u093E\u0930\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u0965\u0967\u0965</p><p class="trans">O\u1E41k\u0101ram bindusa\u1E41yukta\u1E41 nitya\u1E41 dhy\u0101yanti yogina\u1E25 \u0964<br> K\u0101mada\u1E41 mok\u1E63ada\u1E41 caiva O\u1E41k\u0101raya namo nama\u1E25 \u09651\u0965</p><p>\u0421 \u043F\u0435\u0440\u0432\u0438\u0447\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u043E\u044E \u0435\u0434\u0438\u043D,<br> \u0423\u043C\u0430\u043C\u0438 \u0439\u043E\u0433\u043E\u0432 \u0432\u0435\u0447\u043D\u043E \u0437\u0440\u0438\u043C,<br> \u0416\u0435\u043B\u0430\u043D\u044C\u044F, \u0432\u043E\u043B\u044E \u0434\u0430\u0440\u0438\u0442 \u043E\u043D.<br> \u041F\u043E\u043A\u043B\u043E\u043D \u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u0441\u043B\u043E\u0433\u0443 &quot;\u043E\u043C&quot;.</p></div><div class="stanza"><a href="#s2" id="s2" class="num">2</a><p class="sans">\u0928\u092E\u0902\u0924\u093F \u090B\u0937\u092F\u094B \u0926\u0947\u0935\u093E \u0928\u092E\u0928\u094D\u0924\u094D\u092F\u092A\u094D\u0938\u0930\u0938\u093E\u0902 \u0917\u0923\u093E\u0903 \u0964<br> \u0928\u0930\u093E \u0928\u092E\u0902\u0924\u093F \u0926\u0947\u0935\u0947\u0936\u0902 \u0928\u0915\u093E\u0930\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u0965\u0968\u0965</p><p class="trans">Namanti \u1E5B\u1E63ayo dev\u0101 namantyapsaras\u0101\u1E41 ga\u1E47\u0101\u1E25 \u0964<br> Nar\u0101 namanti deve\u015Ba\u1E41 Nak\u0101raya namo nama\u1E25 \u09652\u0965</p><p>\u0411\u043E\u0433\u0430\u043C\u0438, \u0441\u043E\u043D\u043C\u043E\u043C \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u0432,<br> \u0414\u0435\u0432\u0438\u0446 \u043D\u0435\u0431\u0435\u0441\u043D\u044B\u0445 \u0438 \u0436\u0440\u0435\u0446\u043E\u0432,<br> \u041B\u044E\u0434\u044C\u043C\u0438 \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u043E\u0447\u0442\u0435\u043D\u0430...<br> \u041F\u043E\u043A\u043B\u043E\u043D \u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u0441\u043B\u043E\u0433\u0443 &quot;\u043D\u0430&quot;.</p></div><div class="stanza"><a href="#s3" id="s3" class="num">3</a><p class="sans">\u092E\u0939\u093E\u0926\u0947\u0935\u0902 \u092E\u0939\u093E\u0924\u094D\u092E\u093E\u0928\u0902 \u092E\u0939\u093E\u0927\u094D\u092F\u093E\u0928\u0902 \u092A\u0930\u093E\u092F\u0923\u092E\u094D \u0964<br> \u092E\u0939\u093E\u092A\u093E\u092A\u0939\u0930\u0902 \u0926\u0947\u0935\u0902 \u092E\u0915\u093E\u0930\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u0965\u0969\u0965</p><p class="trans">Mah\u0101deva\u1E41 mah\u0101tm\u0101na\u1E41 mah\u0101dhy\u0101na\u1E41 par\u0101ya\u1E47am \u0964<br> Mah\u0101p\u0101pahara\u1E41 deva\u1E41 Mak\u0101raya namo nama\u1E25 \u09653\u0965</p><p>\u0412\u0435\u043B\u0438\u043A\u0438\u0439 \u0434\u0443\u0445, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0431\u043E\u0433,<br> \u0412\u0435\u043B\u0438\u043A\u0438\u0445 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0439 \u0441\u043B\u043E\u0433,<br> \u041F\u043E\u0440\u043E\u0447\u043D\u043E\u0441\u0442\u044C \u043A\u0435\u043C \u0443\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u0430...<br> \u041F\u043E\u043A\u043B\u043E\u043D \u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u0441\u043B\u043E\u0433\u0443 &quot;\u043C\u0430&quot;.</p></div><div class="stanza"><a href="#s4" id="s4" class="num">4</a><p class="sans">\u0936\u093F\u0935\u0902 \u0936\u093E\u0902\u0924\u0902 \u091C\u0917\u0928\u094D\u0928\u093E\u0925\u0902 \u0932\u094B\u0915\u093E\u0928\u0941\u0917\u094D\u0930\u0939\u0915\u093E\u0930\u0915\u092E\u094D \u0964<br> \u0936\u093F\u0935\u092E\u0947\u0915\u092A\u0926\u0902 \u0928\u093F\u0924\u094D\u092F\u0902 \u0936\u093F\u0915\u093E\u0930\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u0965\u096A\u0965</p><p class="trans">\u015Aiva\u1E41 \u015B\u0101nta\u1E41 jaganann\u0101tha\u1E41 lok\u0101nugrahak\u0101rakam \u0964<br> \u015Aivamekapada\u1E41 nitya\u1E41 \u015Aik\u0101raya namo nama\u1E25 \u09654\u0965</p><p>\u0411\u043B\u0430\u0433\u043E\u0439 \u0432\u043B\u0430\u0434\u044B\u043A\u0430 \u0432\u0441\u0435\u0445 \u043C\u0438\u0440\u043E\u0432,<br> \u0411\u044B\u0442\u044C\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0438 \u043F\u043E\u043A\u0440\u043E\u0432,<br> \u041E\u043F\u043E\u0440\u0430 \u0432\u0435\u0447\u043D\u043E\u0441\u0442\u0438 \u0442\u0438\u0448\u0438...<br> \u041F\u043E\u043A\u043B\u043E\u043D \u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u0441\u043B\u043E\u0433\u0443 &quot;\u0448\u0438&quot;.</p></div><div class="stanza"><a href="#s5" id="s5" class="num">5</a><p class="sans">\u0935\u093E\u0939\u0928\u0902 \u0935\u0943\u0937\u092D\u094B \u092F\u0938\u094D\u092F \u0935\u093E\u0938\u0941\u0915\u093F\u0903 \u0915\u0902\u0920\u092D\u0942\u0937\u0923\u092E\u094D \u0964<br> \u0935\u093E\u092E\u0947 \u0936\u0915\u094D\u0924\u093F\u0927\u0930\u0902 \u0926\u0947\u0935\u0902 \u0935\u0915\u093E\u0930\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u0965\u096B\u0965</p><p class="trans">V\u0101hana\u1E41 v\u1E5B\u1E63abho yasya v\u0101suki\u1E25 ka\u1E47\u1E6Dhabhu\u1E63a\u1E47a\u1E41 V\u0101me \u015Bakti dhara\u1E41 deva\u1E41 V\u0101karaya namo nama\u1E25 \u09655\u0965</p><p>\u041D\u0430 \u043C\u0443\u0434\u0440\u043E\u043C \u0435\u0437\u0434\u044F\u0449\u0438\u0439 \u0431\u044B\u043A\u0435,<br> \u0411\u043E\u0433\u0438\u043D\u044E \u0434\u0435\u0440\u0436\u0430\u0449\u0438\u0439 \u0432 \u0440\u0443\u043A\u0435,<br> \u0427\u044C\u044F \u0437\u043C\u0435\u0435\u043C \u0448\u0435\u044F \u043E\u0431\u0432\u0438\u0442\u0430...<br> \u041F\u043E\u043A\u043B\u043E\u043D \u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u0441\u043B\u043E\u0433\u0443 &quot;\u0432\u0430&quot;.</p></div><div class="stanza"><a href="#s6" id="s6" class="num">6</a><p class="sans">\u092F\u0924\u094D\u0930 \u092F\u0924\u094D\u0930 \u0938\u094D\u0925\u093F\u0924\u094B \u0926\u0947\u0935\u0903 \u0938\u0930\u094D\u0935\u0935\u094D\u092F\u093E\u092A\u0940 \u092E\u0939\u0947\u0936\u094D\u0935\u0930\u0903 \u0964<br> \u092F\u094B \u0917\u0941\u0930\u0941\u0903 \u0938\u0930\u094D\u0935\u0926\u0947\u0935\u093E\u0928\u093E\u0902 \u092F\u0915\u093E\u0930\u093E\u092F \u0928\u092E\u094B \u0928\u092E\u0903 \u0965\u096C\u0965</p><p class="trans">Yatra yatra sthito deva sarvavy\u0101p\u012B mahe\u015Bvara\u1E25 Yo guru\u1E25 sarvadev\u0101n\u0101\u1E41 Yakaraya namo nama\u1E25 \u09656\u0965</p><p>\u041F\u043E\u0434\u0432\u0438\u0436\u043D\u044B\u0439 \u0438 \u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u0411\u043E\u0433,<br> \u0411\u043E\u0433\u043E\u0432 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A, \u0432\u0435\u0447\u043D\u044B\u0439 \u0441\u043B\u043E\u0433,<br> \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u0411\u044B\u0442\u0438\u044F...<br> \u041F\u043E\u043A\u043B\u043E\u043D \u0434\u0430 \u0431\u0443\u0434\u0435\u0442 \u0441\u043B\u043E\u0433\u0443 &quot;\u0439\u0430&quot;.</p></div><div class="stanza"><a href="#s7" id="s7" class="num">7</a><p class="sans">\u0937\u0921\u0915\u094D\u0937\u0930\u092E\u093F\u0926\u0902 \u0938\u094D\u0924\u094B\u0924\u094D\u0930\u0902 \u092F\u0903 \u092A\u0920\u0947\u091A\u094D\u091B\u093F\u0935\u0938\u0902\u0928\u093F\u0927\u094C \u0964<br> \u0936\u093F\u0935\u0932\u094B\u0915\u092E\u0935\u093E\u092A\u094D\u0928\u094B\u0924\u093F \u0936\u093F\u0935\u0947\u0928 \u0938\u0939 \u092E\u094B\u0926\u0924\u0947 \u0965 \u096D\u0965</p><p class="trans">\u1E63a\u1E0Dak\u1E63aramida\u1E43 stotra\u1E43 ya\u1E25 pa\u1E6Dhecchivasa\u1E43nidhau \u0964<br> \u015Bivalokamav\u0101pnoti \u015Bivena saha modate \u09657\u0965</p><p>\u041A\u0442\u043E \u044D\u0442\u043E\u0442 \u0433\u0438\u043C\u043D \u0448\u0435\u0441\u0442\u0438 \u0441\u043B\u043E\u0433\u0430\u043C<br> \u0427\u0438\u0442\u0430\u0435\u0442, \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u044B\u0439 \u0431\u043E\u0433\u0430\u043C,<br> \u041D\u0435\u043A\u0442\u0430\u0440 \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0438\u0437\u043E\u043F\u044C\u0451\u0442<br> \u0412 \u0442\u043E\u043C \u043C\u0438\u0440\u0435, \u0428\u0438\u0432\u0430 \u0433\u0434\u0435 \u0436\u0438\u0432\u0451\u0442.</p></div><div class="stanza"><p class="sans">\u0965 \u0907\u0924\u093F \u0936\u094D\u0930\u0940 \u0930\u0941\u0926\u094D\u0930\u092F\u093E\u092E\u0932\u0947 \u0909\u092E\u093E\u092E\u0939\u0947\u0936\u094D\u0935\u0930\u0938\u0902\u0935\u093E\u0926\u0947 \u0937\u0921\u0915\u094D\u0937\u0930\u0938\u094D\u0924\u094B\u0924\u094D\u0930\u0902 \u0938\u092E\u094D\u092A\u0942\u0930\u094D\u0923\u092E\u094D \u0965</p><p class="trans">\u0965 iti \u015Br\u012B rudray\u0101male um\u0101mahe\u015Bvarasa\u1E43v\u0101de \u1E63a\u1E0Dak\u1E63arastotra\u1E43 samp\u016Br\u1E47am \u0965</p><p>\u0422\u0430\u043A \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F \u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u0439\u0441\u044F \u0432 &quot;\u0420\u0443\u0434\u0440\u0430\u044F\u043C\u0430\u043B\u0430-\u0442\u0430\u043D\u0442\u0440\u0435&quot;, \u0432 \u0431\u0435\u0441\u0435\u0434\u0435 \u0423\u043C\u044B \u0438 \u041C\u0430\u0445\u0435\u0448\u0432\u0430\u0440\u044B \xAB\u0413\u0438\u043C\u043D \u0448\u0435\u0441\u0442\u0438 \u0441\u043B\u043E\u0433\u0430\u043C \u043C\u0430\u043D\u0442\u0440\u044B \u0428\u0438\u0432\u044B\xBB.</p></div><h2 id="\u0432\u0430\u0440\u0438\u0430\u043D\u0442-\u0430\u043A\u043A\u043E\u043C\u043F\u0430\u043D\u0435\u043C\u0435\u043D\u0442\u0430" tabindex="-1">\u0412\u0430\u0440\u0438\u0430\u043D\u0442 \u0430\u043A\u043A\u043E\u043C\u043F\u0430\u043D\u0435\u043C\u0435\u043D\u0442\u0430 <a class="header-anchor" href="#\u0432\u0430\u0440\u0438\u0430\u043D\u0442-\u0430\u043A\u043A\u043E\u043C\u043F\u0430\u043D\u0435\u043C\u0435\u043D\u0442\u0430" aria-hidden="true">#</a></h2><p>\u0420\u0430\u0437\u043C\u0435\u0440 \u2014 \u0430\u043D\u0443\u0448\u0442\u0443\u0431\u0445. <img src="'+n+'" alt=""></p>',11),e=[i];function d(o,c,m,l,v,h){return r(),s("div",null,e)}var _=a(p,[["render",d]]);export{u as __pageData,_ as default};
